import React from "react";
import {Tooltip as PrimeTooltip} from "primereact/tooltip";
import type {TooltipProps} from '@lmb-it/kitsconcerto-types'

const Tooltip = ({
  children,
  label,
  tooltipProps,
  ...props
}:TooltipProps) => {
  //unique has
  const uniqueHash = Math.floor(Math.random() * 100);
  const className = `tooltip-order-${uniqueHash}`;

  return (
    <React.Fragment>
      <PrimeTooltip target={"." + className} {...props} />

      <div className={className} data-pr-tooltip={label} {...tooltipProps}>
        {children}
      </div>
    </React.Fragment>
  );
};

export default Tooltip;
